/**
 * Returns a static named barangay list for cities where the PSGC API
 * returns generic numbered names. Returns null to use the API result.
 * Accepts any code format (6-digit, 9-digit, etc.)
 */
function getStaticBarangays(cityCode) {
  const codeStr = (cityCode || "").toString().trim();
  // Try exact match first (handles 9-digit codes)
  if (STATIC_BARANGAYS[codeStr]) {
    return STATIC_BARANGAYS[codeStr].map((name, i) => ({
      name,
      code: codeStr + "_static_" + i,
    }));
  }
  // Try 6-digit prefix match
  const code6 = codeStr.replace(/\D/g, "").substring(0, 6);
  const list = STATIC_BARANGAYS[code6];
  if (!list) return null;
  return list.map((name, i) => ({
    name,
    code: code6 + "_static_" + i,
  }));
}

