// ============================================================
// PSGC DATA LOADERS
// ============================================================
async function loadAllCities() {
  if (allCitiesCache) return allCitiesCache;
  try {
    const res = await fetch(`${PSGC_BASE}/cities-municipalities.json`);
    if (res.ok) {
      const data = await res.json();
      allCitiesCache = data.sort((a, b) => a.name.localeCompare(b.name));
    }
  } catch (err) {
    console.warn("PSGC cities load failed:", err);
    allCitiesCache = [];
  }
  return allCitiesCache || [];
}

async function loadAllProvinces() {
  if (allProvincesCache) return allProvincesCache;
  try {
    // Load provinces + regions in parallel (regions cover NCR, BARMM, etc.)
    const [provRes, regRes] = await Promise.all([
      fetch(`${PSGC_BASE}/provinces.json`),
      fetch(`${PSGC_BASE}/regions.json`),
    ]);
    const provinces = provRes.ok ? await provRes.json() : [];
    const regions   = regRes.ok  ? await regRes.json()  : [];

    // Regions that have no province (NCR, BARMM, etc.) go in the list as-is
    const NO_PROVINCE_REGIONS = ["130000000","190000000","990000000"];
    const regionEntries = regions
      .filter(r => NO_PROVINCE_REGIONS.includes(r.code))
      .map(r => ({ code: r.code, name: r.name, isRegion: true }));

    const all = [
      ...provinces.map(p => ({ code: p.code, name: p.name, isRegion: false })),
      ...regionEntries,
    ].sort((a, b) => a.name.localeCompare(b.name));

    allProvincesCache = all;
  } catch (err) {
    console.warn("Province load failed:", err);
    allProvincesCache = [];
  }
  return allProvincesCache || [];
}

async function loadCitiesForProvince(provCode, isRegion) {
  try {
    const segment = isRegion ? "regions" : "provinces";
    const res = await fetch(`${PSGC_BASE}/${segment}/${provCode}/cities-municipalities.json`);
    if (res.ok) {
      const data = await res.json();
      return data.sort((a, b) => a.name.localeCompare(b.name));
    }
  } catch (err) {
    console.warn("City load failed:", err);
  }
  return [];
}

async function loadBarangaysForCity(code, cityName) {
  // Check by city NAME first — 100% reliable regardless of code format
  if (cityName) {
    const nameKey = cityName.toLowerCase().trim();
    const byName = STATIC_BARANGAYS_BY_NAME[nameKey];
    if (byName) {
      return byName.map((name, i) => ({ name, code: nameKey + "_static_" + i }));
    }
  }
  // Also check by code (both exact and 6-digit prefix)
  const staticList = getStaticBarangays(code);
  if (staticList) return staticList;

  try {
    const res = await fetch(`${PSGC_BASE}/cities-municipalities/${code}/barangays.json`);
    if (res.ok) {
      const data = await res.json();
      return data.sort((a, b) => a.name.localeCompare(b.name));
    }
  } catch (err) {
    console.warn("PSGC barangays load failed:", err);
  }
  return [];
}

// ============================================================
// INIT COMBOBOXES
// ============================================================
let provinceCombo = null;
let cityCombo     = null;
let barangayCombo = null;

function initAddressComboboxes() {
  const provinceInput = document.getElementById("province");
  const cityInput     = document.getElementById("city");
  const barangayInput = document.getElementById("barangay");
  const zipcodeInput  = document.getElementById("zipcode");
  if (!cityInput || !barangayInput) return;

  // ---- BARANGAY COMBOBOX ----
  barangayCombo = makeCombobox(barangayInput, {
    placeholder: "Search Barangay…",
    onSelect(item) {
      if (zipcodeInput) {
        zipcodeInput.value = getZipFromBarangay(item.label, currentCityZip);
      }
    },
    onOpen({ showLoading, renderList, setItems }) {
      if (currentBarangays.length === 0) {
        showLoading("Select City/Municipality first…");
        return;
      }
      const items = currentBarangays.map(b => ({
        label: b.name,
        value: b.code,
        zip:   getZipFromBarangay(b.name, currentCityZip),
      }));
      setItems(items);
      renderList();
    },
  });

  // ---- CITY COMBOBOX ----
  cityCombo = makeCombobox(cityInput, {
    placeholder: "Select province first…",
    onSelect: async item => {
      selectedCityCode = item.value;

      const cityZip = getZipCode(item.label, item.value);
      currentCityZip = cityZip;
      if (zipcodeInput) zipcodeInput.value = cityZip;

      // Reset barangay
      barangayInput.value = "";
      currentBarangays = [];
      if (barangayCombo) barangayCombo.setItems([]);

      barangayInput.placeholder = "Loading barangays…";
      currentBarangays = await loadBarangaysForCity(selectedCityCode, item.label);
      barangayInput.placeholder = "Select Barangay";
      if (barangayCombo) {
        barangayCombo.setItems(
          currentBarangays.map(b => ({
            label: b.name,
            value: b.code,
            zip:   getZipFromBarangay(b.name, currentCityZip),
          }))
        );
      }
    },
    onOpen({ showLoading, renderList, setItems }) {
      if (currentCities.length === 0) {
        showLoading("Select Province first…");
        return;
      }
      const items = currentCities.map(c => ({
        label: c.name,
        value: c.code,
        zip:   getZipCode(c.name, c.code),
      }));
      setItems(items);
      renderList();
    },
  });

  // ---- PROVINCE COMBOBOX ----
  if (provinceInput) {
    provinceCombo = makeCombobox(provinceInput, {
      placeholder: "Search Province or Region…",
      onSelect: async item => {
        // Reset dependent fields
        cityInput.value     = "";
        barangayInput.value = "";
        if (zipcodeInput) zipcodeInput.value = "";
        currentCities    = [];
        currentBarangays = [];
        currentCityZip   = "";
        if (cityCombo)     cityCombo.setItems([]);
        if (barangayCombo) barangayCombo.setItems([]);

        cityInput.placeholder = "Loading cities…";
        currentCities = await loadCitiesForProvince(item.value, item.isRegion);
        cityInput.placeholder = "Select City / Municipality";
        if (cityCombo) {
          cityCombo.setItems(currentCities.map(c => ({
            label: c.name,
            value: c.code,
            zip:   getZipCode(c.name, c.code),
          })));
        }
      },
      onOpen: async ({ showLoading, renderList, setItems }) => {
        showLoading("Loading provinces…");
        const provinces = await loadAllProvinces();
        const items = provinces.map(p => ({
          label:    p.name,
          value:    p.code,
          isRegion: p.isRegion,
        }));
        setItems(items);
        renderList();
      },
    });
  }

  loadAllProvinces(); // preload in background
}

document.addEventListener("DOMContentLoaded", () => {
  injectStyles();
  initAddressComboboxes();
});

